export type ColorValue = string | RGB | RGBA | HSV | HSVA | HSL | HSLA;

export interface RGB {
  r: number;
  g: number;
  b: number;
}

export type RGBA = RGB
  & ObjectWithAlpha;

export interface ObjectWithAlpha {
  a: number;
}

export interface HSV {
  h: number;
  s: number;
  v: number;
}

export type HSVA = HSV
  & ObjectWithAlpha;

export interface HSL {
  h: number;
  s: number;
  l: number;
}

export type HSLA = HSL
  & ObjectWithAlpha;